/**
 * Metadata collection types and interfaces
 */
/**
 * Base interface for all metadata collectors
 */
interface MetadataCollector<T = Record<string, unknown>> {
    /**
     * Collect metadata asynchronously
     * Should handle errors gracefully and return partial data
     */
    collect(): Promise<T>;
    /**
     * Get collector name for debugging
     */
    getName(): string;
}
/**
 * Result of metadata collection with error tracking
 */
interface MetadataCollectionResult<T = Record<string, unknown>> {
    /**
     * Collected data (may be partial on errors)
     */
    data: T;
    /**
     * Whether collection was successful
     */
    success: boolean;
    /**
     * Error message if collection failed
     */
    error?: string;
    /**
     * Collection duration in milliseconds
     */
    duration: number;
    /**
     * Collector name
     */
    collector: string;
}
/**
 * Git metadata structure
 */
interface GitMetadata {
    branch?: string;
    commit?: {
        hash?: string;
        message?: string;
        author?: string;
        authorId?: string;
        email?: string;
        timestamp?: string;
        isDirty?: boolean;
    };
    repository?: {
        name?: string;
        url?: string;
    };
    pr?: PRMetadata;
}
/**
 * CI metadata structure
 */
interface CIMetadata {
    provider?: string;
    pipeline?: {
        id?: string;
        name?: string;
        url?: string;
    };
    build?: {
        number?: string;
        trigger?: string;
    };
    environment?: {
        name?: string;
        type?: string;
        os?: string;
        node?: string;
    };
}
/**
 * Pull Request metadata structure
 */
interface PRMetadata {
    title?: string;
    number?: number;
    url?: string;
    status?: string;
    branch?: string;
    targetBranch?: string;
    author?: string;
    labels?: string[];
    merged?: boolean;
    mergeable?: boolean;
    mergeCommitSha?: string;
}
/**
 * System metadata structure
 */
interface SystemMetadata {
    os?: string;
    cpu?: string;
    memory?: string;
    nodeVersion?: string;
    platform?: string;
    hostname?: string;
}
/**
 * Test case metadata in skeleton
 */
interface SkeletonTest {
    testId: string;
    title: string;
    location: {
        file: string;
        line: number;
        column: number;
    };
    tags?: string[];
    expectedStatus?: string;
    annotations?: Array<{
        type: string;
        description?: string;
    }>;
}
/**
 * Suite metadata in skeleton (recursive structure)
 */
interface SkeletonSuite {
    title: string;
    file?: string;
    type: 'describe' | 'file';
    location?: {
        file: string;
        line: number;
        column: number;
    };
    tests: SkeletonTest[];
    suites?: SkeletonSuite[];
}
/**
 * Test run skeleton structure
 */
interface RunSkeleton {
    totalTests: number;
    suites: SkeletonSuite[];
}
/**
 * Project use options (browser, viewport, etc.)
 * @see docs/PLAYWRIGHT-TYPES-REFERENCE.md
 */
interface ProjectUseOptions {
    browserName?: 'chromium' | 'firefox' | 'webkit';
    channel?: string;
    headless?: boolean;
    viewport?: {
        width: number;
        height: number;
    } | null;
    baseURL?: string;
    trace?: 'off' | 'on' | 'retain-on-failure' | 'on-first-retry' | string;
    screenshot?: 'off' | 'on' | 'only-on-failure' | string;
    video?: 'off' | 'on' | 'retain-on-failure' | 'on-first-retry' | string;
    isMobile?: boolean;
    locale?: string;
}
/**
 * Project configuration (from FullProject)
 * @see docs/PLAYWRIGHT-TYPES-REFERENCE.md
 */
interface ProjectConfig {
    name: string;
    testDir?: string;
    timeout?: number;
    retries?: number;
    repeatEach?: number;
    dependencies?: string[];
    grep?: string[];
    use?: ProjectUseOptions;
}
/**
 * Playwright metadata structure
 *
 * @see docs/PLAYWRIGHT-TYPES-REFERENCE.md for field sources and extraction details
 */
interface PlaywrightMetadata {
    version?: string;
    parallel?: boolean;
    workers?: number;
    shard?: ShardMetadata;
    projects?: ProjectConfig[];
    browsers?: string[];
    configFile?: string;
    forbidOnly?: boolean;
    fullyParallel?: boolean;
    globalTimeout?: number;
    grep?: string[];
    maxFailures?: number;
    metadata?: Record<string, unknown>;
    reportSlowTests?: {
        max: number;
        threshold: number;
    };
    rootDir?: string;
    tags?: string[];
    webServer?: Record<string, unknown>;
}
/**
 * Shard metadata structure
 */
interface ShardMetadata {
    current?: number;
    total?: number;
}
/**
 * Complete metadata collection result
 */
interface CompleteMetadata {
    git?: GitMetadata;
    ci?: CIMetadata;
    system?: SystemMetadata;
    playwright?: PlaywrightMetadata;
    skeleton?: RunSkeleton;
}
/**
 * Metadata collection summary
 */
interface MetadataCollectionSummary {
    /**
     * Complete collected metadata
     */
    metadata: CompleteMetadata;
    /**
     * Collection results for each collector
     */
    results: MetadataCollectionResult[];
    /**
     * Total collection time in milliseconds
     */
    totalDuration: number;
    /**
     * Number of successful collectors
     */
    successCount: number;
    /**
     * Number of failed collectors
     */
    failureCount: number;
}

/**
 * Coverage type definitions for TestDino Playwright integration.
 * Istanbul-only (V8 coverage planned for future release).
 */
/**
 * Istanbul coverage map format (window.__coverage__).
 * Contains structural metadata + execution counts per file.
 * Does NOT contain source code.
 */
type IstanbulCoverageMap = Record<string, IstanbulFileCoverage>;
interface IstanbulFileCoverage {
    path: string;
    statementMap: Record<string, {
        start: {
            line: number;
            column: number;
        };
        end: {
            line: number;
            column: number;
        };
    }>;
    fnMap: Record<string, {
        name: string;
        decl: {
            start: {
                line: number;
                column: number;
            };
            end: {
                line: number;
                column: number;
            };
        };
        loc: {
            start: {
                line: number;
                column: number;
            };
            end: {
                line: number;
                column: number;
            };
        };
    }>;
    branchMap: Record<string, {
        type: string;
        loc: {
            start: {
                line: number;
                column: number;
            };
            end: {
                line: number;
                column: number;
            };
        };
        locations: Array<{
            start: {
                line: number;
                column: number;
            };
            end: {
                line: number;
                column: number;
            };
        }>;
    }>;
    /** Statement execution counts */
    s: Record<string, number>;
    /** Function call counts */
    f: Record<string, number>;
    /** Branch path counts */
    b: Record<string, number[]>;
}
/**
 * Coverage fragment collected per-test by the fixture.
 * Attached to testInfo as 'testdino-coverage' attachment.
 */
interface CoverageFragment {
    istanbul: IstanbulCoverageMap | null;
}
/**
 * Metric with total, covered count, and optional percentage.
 * The pct field is calculated on the server/client and not sent over the wire.
 */
interface CoverageMetric {
    total: number;
    covered: number;
    /** Coverage percentage (0-100), calculated from total and covered */
    pct: number;
}
/**
 * Summary metrics for a coverage report.
 */
interface CoverageSummary {
    lines: CoverageMetric;
    branches: CoverageMetric;
    functions: CoverageMetric;
    statements: CoverageMetric;
}
/**
 * Per-file coverage metrics (no source code, no raw maps).
 */
interface FileCoverage {
    path: string;
    lines: CoverageMetric;
    branches: CoverageMetric;
    functions: CoverageMetric;
    statements: CoverageMetric;
}
/**
 * Compact per-file hit counts for cross-shard merging.
 * Contains only execution counts and totals — no structural maps,
 * no source code, no line/column data.
 */
interface CompactFileCounts {
    /** Statement execution counts */
    s: Record<string, number>;
    /** Function call counts */
    f: Record<string, number>;
    /** Branch path counts */
    b: Record<string, number[]>;
    /** Denominators computed from structural maps */
    totals: {
        s: number;
        f: number;
        b: number;
    };
    /** Hash of structural map shape for build mismatch detection */
    shapeHash: string;
}
/**
 * Compact coverage data for sharded uploads.
 * Sent as part of coverage:data event for server-side merging.
 */
interface CompactCoverageData {
    files: Record<string, CompactFileCounts>;
    fileCount: number;
}
/**
 * Coverage threshold percentages.
 * If set, the run fails when coverage drops below these values.
 */
interface CoverageThresholds {
    statements?: number;
    branches?: number;
    functions?: number;
    lines?: number;
}
/**
 * Coverage configuration options (part of TestdinoConfig).
 */
interface CoverageConfig {
    /** Enable coverage collection. Default: false */
    enabled: boolean;
    /** Glob patterns — only files whose path matches a pattern are included */
    include?: string[];
    /** Glob patterns — files whose path matches a pattern are excluded */
    exclude?: string[];
    /** Fail the run if coverage percentages are below these thresholds */
    thresholds?: CoverageThresholds;
}

type CoverageFixtures = {
    _testdinoCoverage: void;
};
declare const coverageFixtures: {
    _testdinoCoverage: ((({ page }: {
        page: Page;
    }, use: () => Promise<void>, testInfo: TestInfo) => Promise<void>) | {
        auto: boolean;
    })[];
};
/**
 * Pre-extended test with coverage fixtures for direct import.
 *
 * Usage:
 * ```typescript
 * import { test, expect } from '@testdino/playwright';
 *
 * test('my test', async ({ page }) => {
 *   // coverage collected automatically
 * });
 * ```
 */
declare const test: playwright_test.TestType<playwright_test.PlaywrightTestArgs & playwright_test.PlaywrightTestOptions & CoverageFixtures, playwright_test.PlaywrightWorkerArgs & playwright_test.PlaywrightWorkerOptions>;

/**
 * Server error classes for quota and infrastructure errors
 * These are received from the TestDino server and handled gracefully in the reporter
 * Follows the same Error class pattern as cli/errors.ts
 */
/**
 * Base class for all TestDino server errors
 * Extends Error to work with standard error handling
 */
declare class TestDinoServerError extends Error {
    readonly code: string;
    constructor(code: string, message: string);
}
/**
 * Quota exhausted error (session creation)
 * HTTP 402 response when organization pool is exhausted
 */
declare class QuotaExhaustedError extends TestDinoServerError {
    readonly details: {
        planName: string;
        totalLimit: number;
        used: number;
        resetDate?: string;
    };
    constructor(message: string, details: {
        planName: string;
        totalLimit: number;
        used: number;
        resetDate?: string;
    });
}
/**
 * Quota exceeded error (run:begin)
 * WebSocket NACK when test count exceeds available quota
 */
declare class QuotaExceededError extends TestDinoServerError {
    readonly details: {
        planName: string;
        totalTests: number;
        remaining: number;
        used: number;
        total: number;
        resetDate?: string;
        canPartialSubmit: boolean;
        allowedCount: number;
    };
    constructor(message: string, details: {
        planName: string;
        totalTests: number;
        remaining: number;
        used: number;
        total: number;
        resetDate?: string;
        canPartialSubmit: boolean;
        allowedCount: number;
    });
}
/**
 * Union type for all server error classes
 */
type ServerError = QuotaExhaustedError | QuotaExceededError;

/**
 * Server response type definitions
 * These are pure type definitions for server responses (not Error classes)
 * Error classes are in reporter/errors.ts following the established pattern
 */

/**
 * HTTP 402 response from session creation
 * This is a server response type, not an error class
 */
interface SessionCreationQuotaResponse {
    success: false;
    message: string;
    error: 'QUOTA_EXHAUSTED';
    details: {
        planName: string;
        totalLimit: number;
        used: number;
        resetDate?: string;
    };
}
/**
 * WebSocket NACK message structure
 * This is a server message type, not an error class
 */
interface NackMessage {
    type: 'nack';
    eventId: string;
    error: string | ServerError;
    retryable: boolean;
    timestamp: number;
}

/**
 * Core types for TestDino Playwright integration
 */

interface TestdinoConfig {
    /**
     * Record token for authentication
     */
    token?: string;
    /**
     * CI run ID for grouping sharded runs
     */
    ciRunId?: string;
    /**
     * Server URL (for development/testing)
     */
    serverUrl?: string;
    /**
     * Enable debug logging
     */
    debug?: boolean;
    /**
     * Upload artifacts (screenshots, videos, traces) to cloud storage
     * Default: true (enabled)
     * Set to false or use --no-artifacts CLI flag to disable
     */
    artifacts?: boolean;
    /**
     * Coverage collection configuration.
     * When enabled, Istanbul coverage is collected per-test via fixtures,
     * merged in the reporter, and uploaded as metrics to the server.
     */
    coverage?: CoverageConfig;
}
interface EventBuffer {
    events: TestEvent[];
    maxSize: number;
    flush: () => Promise<void>;
    add: (event: TestEvent) => Promise<void>;
}
interface ConnectionConfig {
    token: string;
    serverUrl: string;
    maxRetries?: number;
    retryDelay?: number;
}
type TestEvent = TestRunBeginEvent | TestBeginEvent | TestStepBeginEvent | TestStepEndEvent | TestEndEvent | TestRunEndEvent | TestRunErrorEvent | TestConsoleOutEvent | TestConsoleErrEvent | CoverageDataEvent;
interface Annotation {
    type: string;
    description?: string;
}
interface BaseEvent {
    type: string;
    timestamp: number;
    runId: string;
    sequence: number;
}
interface TestRunBeginEvent extends BaseEvent {
    type: 'run:begin';
    projectId: string;
    metadata: CompleteMetadata;
    ciRunId?: string;
}
interface TestBeginEvent extends BaseEvent {
    type: 'test:begin';
    testId: string;
    title: string;
    titlePath: Array<string>;
    location: {
        file: string;
        line: number;
        column: number;
    };
    tags: Array<string>;
    expectedStatus: 'passed' | 'failed' | 'timedOut' | 'skipped' | 'interrupted';
    timeout: number;
    retries: number;
    annotations: Array<Annotation>;
    retry: number;
    workerIndex: number;
    parallelIndex: number;
    repeatEachIndex?: number;
    parentSuite: {
        title: string;
        type: 'root' | 'project' | 'file' | 'describe';
        location?: {
            file: string;
            line: number;
            column: number;
        };
    };
    startTime: number;
}
interface TestStepBeginEvent extends BaseEvent {
    type: 'step:begin';
    testId: string;
    stepId: string;
    title: string;
    titlePath: Array<string>;
    category: string;
    location?: {
        file: string;
        line: number;
        column: number;
    };
    parentStep?: {
        title: string;
        category: string;
        location?: {
            file: string;
            line: number;
            column: number;
        };
    };
    startTime: number;
    retry: number;
    workerIndex: number;
    parallelIndex: number;
    annotations: Array<Annotation>;
}
interface TestStepEndEvent extends BaseEvent {
    type: 'step:end';
    testId: string;
    stepId: string;
    title?: string;
    titlePath?: string[];
    duration: number;
    error?: {
        message: string;
        stack?: string;
        snippet?: string;
        value?: string;
        location?: {
            file: string;
            line: number;
            column: number;
        };
    };
    status: 'passed' | 'failed';
    childSteps: {
        count: number;
        steps: Array<{
            title: string;
            status: 'passed' | 'failed';
        }>;
    };
    workerIndex: number;
    parallelIndex: number;
    attachments: Array<{
        name: string;
        contentType: string;
        path?: string;
    }>;
    annotations?: Array<Annotation>;
    retry: number;
}
interface TestEndEvent extends BaseEvent {
    type: 'test:end';
    testId: string;
    status: 'passed' | 'failed' | 'skipped' | 'timedOut' | 'interrupted';
    outcome: 'expected' | 'unexpected' | 'flaky' | 'skipped';
    duration: number;
    retry: number;
    workerIndex: number;
    parallelIndex: number;
    annotations: Array<Annotation>;
    errors: Array<{
        message: string;
        stack?: string;
        snippet?: string;
        value?: string;
        location?: {
            file: string;
            line: number;
            column: number;
        };
    }>;
    steps: {
        total: number;
        passed: number;
        failed: number;
    };
    attachments: Array<{
        name: string;
        contentType: string;
        path?: string;
    }>;
    stdout?: string[];
    stderr?: string[];
}
interface TestRunEndEvent extends BaseEvent {
    type: 'run:end';
    status: 'passed' | 'failed' | 'timedout' | 'interrupted';
    duration: number;
    startTime: number;
    shard?: {
        current: number;
        total: number;
    };
}
/**
 * Coverage data event — sent after all tests complete, before run:end.
 *
 * Non-sharded runs: contains computed summary + per-file metrics.
 * Sharded runs: contains compact hit counts for server-side cross-shard merging.
 */
interface CoverageDataEvent extends BaseEvent {
    type: 'coverage:data';
    summary: CoverageSummary;
    files: FileCoverage[];
    compactCounts?: CompactCoverageData;
    metadata: {
        instrumentationType: 'istanbul';
        fileCount: number;
        sharded: boolean;
    };
    shard?: {
        current: number;
        total: number;
    };
}
interface TestRunErrorEvent extends BaseEvent {
    type: 'run:error';
    error: {
        message?: string;
        stack?: string;
        value?: string;
        snippet?: string;
        location?: {
            file: string;
            line: number;
            column: number;
        };
        cause?: {
            message?: string;
            stack?: string;
            value?: string;
            snippet?: string;
            location?: {
                file: string;
                line: number;
                column: number;
            };
        };
    };
}
interface TestConsoleOutEvent extends BaseEvent {
    type: 'console:out';
    text: string;
    testId?: string;
    retry?: number;
    truncated?: boolean;
}
interface TestConsoleErrEvent extends BaseEvent {
    type: 'console:err';
    text: string;
    testId?: string;
    retry?: number;
    truncated?: boolean;
}

